    <style>
        /* CSS 样式 */
        #container {
            text-align: center;
            margin-top: 30px;
        }
        input[type="text"] {
            width: 300px;
            font-size: 16px;
            padding: 12px 20px;
            margin: 8px 0;
            box-sizing: border-box;
        }
        input[type="submit"] {
            background-color: #4CAF50;
            color: white;
            padding: 14px 20px;
            margin: 8px 0;
