            cursor: pointer;
        }
        .result {
            margin-top: 30px;
            font-size: 18px;
        }
    </style>
</head>
<body>
    <div id="container">
        <form action="/" method="post">
            <h2>4字节浮点与内存转换</h2>
            <input type="text" name="input_float" placeholder="请输入浮点数">
            <input type="submit" value="转换">
        </form>
        {% if hex_str %}
            <div class="result">内存值：{{ hex_str }}</div>
        {% endif %}
    </div>
